{

    AVIOContext *pb = s->pb;

    AVStream *st;

    int version;

    uint32_t text_offset, data_offset, channel_assign;

    char playback_time[AV_TIMECODE_STR_SIZE];



    st = avformat_new_stream(s, NULL);

    if (!st)

