            uint8_t profile_iop;

            uint8_t level_idc;



            buffer[0]   = value[0];

            buffer[1]   = value[1];

            buffer[2]   = '\0';

            profile_idc = strtol(buffer, NULL, 16);

            buffer[0]   = value[2];

            buffer[1]   = value[3];

            profile_iop = strtol(buffer, NULL, 16);

            buffer[0]   = value[4];

            buffer[1]   = value[5];

            level_idc   = strtol(buffer, NULL, 16);



            av_log(codec, AV_LOG_DEBUG,

                   "RTP Profile IDC: %x Profile IOP: %x Level: %x\n",

                   profile_idc, profile_iop, level_idc);

            h264_data->profile_idc = profile_idc;

            h264_data->profile_iop = profile_iop;

            h264_data->level_idc   = level_idc;

        }

    } else if (!strcmp(attr, "sprop-parameter-sets")) {

        codec->extradata_size = 0;

        codec->extradata      = NULL;



        while (*value) {

            char base64packet[1024];

            uint8_t decoded_packet[1024];

            int packet_size;

            char *dst = base64packet;



            while (*value && *value != ','

                   && (dst - base64packet) < sizeof(base64packet) - 1) {

                *dst++ = *value++;

            }

            *dst++ = '\0';



            if (*value == ',')

                value++;



            packet_size = av_base64_decode(decoded_packet, base64packet,

                                           sizeof(decoded_packet));

            if (packet_size > 0) {

                uint8_t *dest = av_malloc(packet_size + sizeof(start_sequence) +

                                          codec->extradata_size +

                                          FF_INPUT_BUFFER_PADDING_SIZE);

                if (!dest) {

                    av_log(codec, AV_LOG_ERROR,

                           "Unable to allocate memory for extradata!");

                    return AVERROR(ENOMEM);

                }

                if (codec->extradata_size) {

                    memcpy(dest, codec->extradata, codec->extradata_size);

                    av_free(codec->extradata);

                }



                memcpy(dest + codec->extradata_size, start_sequence,

                       sizeof(start_sequence));

                memcpy(dest + codec->extradata_size + sizeof(start_sequence),

                       decoded_packet, packet_size);

                memset(dest + codec->extradata_size + sizeof(start_sequence) +

                       packet_size, 0, FF_INPUT_BUFFER_PADDING_SIZE);



                codec->extradata       = dest;

                codec->extradata_size += sizeof(start_sequence) + packet_size;

            }

        }

        av_log(codec, AV_LOG_DEBUG, "Extradata set to %p (size: %d)!",

               codec->extradata, codec->extradata_size);

    }

    return 0;

}

